class Solution:
    def findScore(self, nums):
        n = len(nums)
        marked = [False] * n
        score = 0
        remaining = n
        while remaining > 0:
            best_i = -1
            for i in range(n):
                if not marked[i] and (best_i == -1 or nums[i] < nums[best_i]):
                    best_i = i
            score += nums[best_i]
            for j in (best_i - 1, best_i, best_i + 1):
                if 0 <= j < n and not marked[j]:
                    marked[j] = True
                    remaining -= 1
        return score

