class Solution:
    def findScore(self, nums):
        n = len(nums)
        order = sorted(range(n), key=lambda i: (nums[i], i))
        marked = [False] * n
        score = 0
        for i in order:
            if marked[i]:
                continue
            score += nums[i]
            marked[i] = True
            if i - 1 >= 0:
                marked[i - 1] = True
            if i + 1 < n:
                marked[i + 1] = True
        return score

